def count_words(text):
    counts = {}
    for word in text.split():
        counts[word] = counts.get(word, 0) + 1
    return counts

def min_max_scale(arr):
    mn = min(arr)
    mx = max(arr)
    if mx == mn:
        return [0 for _ in arr]
    return [(x - mn) / (mx - mn) for x in arr]
